  }

  predicate isBarrierOut2(DataFlow::Node node) { DataFlow::flowsToBackEdge(node) }

  predicate isBarrier2(DataFlow::Node node, FlowState2 state) {
    node = SizeBarrier<SizeBarrierInput>::getABarrierNode(state)
  }
}

